                .header("Authorization", "Bearer $token")
                .build()
        } else {
            original
        }
        return chain.proceed(newRequest)
    }
}

class TokenRefreshAuthenticator(
    private val tokenStore: TokenStore,
    private val tokenRefresher: TokenRefresher
