        return response.request.newBuilder()
            .header("Authorization", "Bearer $refreshed")
            .build()
    }

    private fun responseCount(response: Response): Int {
        var res: Response? = response
        var count = 1
        while (true) {
            res = res?.priorResponse ?: break
            count++
        }
        return count
    }
}

